PREFIX goo: <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?county ?year ?sviSocio (COUNT(DISTINCT ?event) AS ?windEvents)
WHERE {
  {
    SELECT (MAX(?y) AS ?recentYear)
    WHERE {
      ?r a goo:SVIRecord ; goo:sviYear ?y .
    }
  }
  ?state goo:statePostalCode "FL" .
  ?county goo:locatedInState ?state .
  ?sviRec a goo:SVIRecord ;
          goo:representsCounty ?county ;
          goo:sviYear ?recentYear ;
          goo:sviSocioeconomicTheme ?sviSocio .
  FILTER (?sviSocio >= 0.75)
  ?event a goo:StormEventRecord ;
         goo:occurredInCounty ?county ;
         goo:stormEventType ?type ;
         goo:eventStartTime ?eventStart .
  FILTER (CONTAINS(LCASE(STR(?type)), "wind") ||
          CONTAINS(LCASE(STR(?type)), "hurricane") ||
          CONTAINS(LCASE(STR(?type)), "tropical"))
  FILTER (YEAR(?eventStart) = ?recentYear)
  BIND (?recentYear AS ?year)
}
GROUP BY ?county ?year ?sviSocio
HAVING (COUNT(DISTINCT ?event) >= 10)
ORDER BY DESC(?windEvents)
LIMIT 10

